   167→                              NPY_ARRAY_CARRAY | NPY_ARRAY_WRITEBACKIFCOPY);
   168→        if (rp == NULL) {
   169→            goto fail;
   170→        }
   171→    }
   172→
   173→    NPY_BEGIN_THREADS_DESCR(PyArray_DESCR(ap));
   174→    n = PyArray_SIZE(ap)/m;
   175→    rptr = (npy_intp *)PyArray_DATA(rp);
   176→    for (ip = PyArray_DATA(ap), i = 0; i < n; i++, ip += elsize*m) {
   177→        arg_func(ip, m, rptr, ap);
   178→        rptr += 1;
   179→    }
   180→    NPY_END_THREADS_DESCR(PyArray_DESCR(ap));
   181→
   182→    Py_DECREF(ap);
   183→    /* Trigger the WRITEBACKIFCOPY if necessary */
   184→    if (out != NULL && out != rp) {
   185→        PyArray_ResolveWritebackIfCopy(rp);
   186→        Py_DECREF(rp);
   187→        rp = out;
   188→        Py_INCREF(rp);
   189→    }
   190→    return (PyObject *)rp;
   191→
   192→ fail:
   193→    Py_DECREF(ap);
   194→    Py_XDECREF(rp);
   195→    return NULL;
   196→}
