   310→/*NUMPY_API
   311→ * Set variance to 1 to bypass square-root calculation and return variance
   312→ * Std
   313→ */
   314→NPY_NO_EXPORT PyObject *
   315→PyArray_Std(PyArrayObject *self, int axis, int rtype, PyArrayObject *out,
   316→            int variance)
   317→{
   318→    return __New_PyArray_Std(self, axis, rtype, out, variance, 0);
   319→}
   320→
   321→NPY_NO_EXPORT PyObject *
   322→__New_PyArray_Std(PyArrayObject *self, int axis, int rtype, PyArrayObject *out,
   323→                  int variance, int num)
   324→{
   325→    PyObject *obj1 = NULL, *obj2 = NULL, *obj3 = NULL;
   326→    PyArrayObject *arr1 = NULL, *arr2 = NULL, *arrnew = NULL;
   327→    PyObject *ret = NULL, *newshape = NULL;
   328→    int i, n;
   329→    npy_intp val;
   330→
   331→    arrnew = (PyArrayObject *)PyArray_CheckAxis(self, &axis, 0);
   332→    if (arrnew == NULL) {
   333→        return NULL;
   334→    }
   335→    /* Compute and reshape mean */
   336→    arr1 = (PyArrayObject *)PyArray_EnsureAnyArray(
   337→                    PyArray_Mean(arrnew, axis, rtype, NULL));
   338→    if (arr1 == NULL) {
   339→        Py_DECREF(arrnew);
   340→        return NULL;
   341→    }
   342→    n = PyArray_NDIM(arrnew);
   343→    newshape = PyTuple_New(n);
   344→    if (newshape == NULL) {
   345→        Py_DECREF(arr1);
   346→        Py_DECREF(arrnew);
   347→        return NULL;
   348→    }
   349→    for (i = 0; i < n; i++) {
   350→        if (i == axis) {
   351→            val = 1;
   352→        }
   353→        else {
   354→            val = PyArray_DIM(arrnew,i);
   355→        }
   356→        PyTuple_SET_ITEM(newshape, i, PyLong_FromSsize_t(val));
   357→    }
   358→    arr2 = (PyArrayObject *)PyArray_Reshape(arr1, newshape);
   359→    Py_DECREF(arr1);
   360→    Py_DECREF(newshape);
   361→    if (arr2 == NULL) {
   362→        Py_DECREF(arrnew);
   363→        return NULL;
   364→    }
   365→
   366→    /* Compute x = x - mx */
   367→    arr1 = (PyArrayObject *)PyArray_EnsureAnyArray(
   368→                PyNumber_Subtract((PyObject *)arrnew, (PyObject *)arr2));
   369→    Py_DECREF(arr2);
   370→    if (arr1 == NULL) {
   371→        Py_DECREF(arrnew);
   372→        return NULL;
   373→    }
   374→    /* Compute x * x */
   375→    if (PyArray_ISCOMPLEX(arr1)) {
   376→        obj3 = PyArray_Conjugate(arr1, NULL);
   377→    }
   378→    else {
   379→        obj3 = (PyObject *)arr1;
   380→        Py_INCREF(arr1);
   381→    }
   382→    if (obj3 == NULL) {
   383→        Py_DECREF(arrnew);
   384→        return NULL;
   385→    }
   386→    arr2 = (PyArrayObject *)PyArray_EnsureAnyArray(
   387→                PyArray_GenericBinaryFunction((PyObject *)arr1, obj3,
   388→                                               n_ops.multiply));
   389→    Py_DECREF(arr1);
   390→    Py_DECREF(obj3);
   391→    if (arr2 == NULL) {
   392→        Py_DECREF(arrnew);
   393→        return NULL;
   394→    }
   395→    if (PyArray_ISCOMPLEX(arr2)) {
   396→        obj3 = PyObject_GetAttrString((PyObject *)arr2, "real");
   397→        switch(rtype) {
   398→        case NPY_CDOUBLE:
   399→            rtype = NPY_DOUBLE;
   400→            break;
   401→        case NPY_CFLOAT:
   402→            rtype = NPY_FLOAT;
   403→            break;
   404→        case NPY_CLONGDOUBLE:
   405→            rtype = NPY_LONGDOUBLE;
   406→            break;
   407→        }
   408→    }
   409→    else {
   410→        obj3 = (PyObject *)arr2;
   411→        Py_INCREF(arr2);
   412→    }
   413→    if (obj3 == NULL) {
   414→        Py_DECREF(arrnew);
   415→        return NULL;
   416→    }
   417→    /* Compute add.reduce(x*x,axis) */
   418→    obj1 = PyArray_GenericReduceFunction((PyArrayObject *)obj3, n_ops.add,
   419→                                         axis, rtype, NULL);
   420→    Py_DECREF(obj3);
   421→    Py_DECREF(arr2);
   422→    if (obj1 == NULL) {
   423→        Py_DECREF(arrnew);
   424→        return NULL;
   425→    }
   426→    n = PyArray_DIM(arrnew,axis);
   427→    Py_DECREF(arrnew);
   428→    n = (n-num);
   429→    if (n == 0) {
   430→        n = 1;
   431→    }
   432→    obj2 = PyFloat_FromDouble(1.0/((double )n));
   433→    if (obj2 == NULL) {
   434→        Py_DECREF(obj1);
   435→        return NULL;
   436→    }
   437→    ret = PyNumber_Multiply(obj1, obj2);
   438→    Py_DECREF(obj1);
   439→    Py_DECREF(obj2);
   440→
   441→    if (!variance) {
   442→        arr1 = (PyArrayObject *)PyArray_EnsureAnyArray(ret);
   443→        /* sqrt() */
   444→        ret = PyArray_GenericUnaryFunction(arr1, n_ops.sqrt);
   445→        Py_DECREF(arr1);
   446→    }
   447→    if (ret == NULL) {
   448→        return NULL;
   449→    }
   450→    if (PyArray_CheckExact(self)) {
   451→        goto finish;
   452→    }
   453→    if (PyArray_Check(self) && Py_TYPE(self) == Py_TYPE(ret)) {
   454→        goto finish;
   455→    }
   456→    arr1 = (PyArrayObject *)PyArray_EnsureArray(ret);
   457→    if (arr1 == NULL) {
   458→        return NULL;
   459→    }
   460→    ret = PyArray_View(arr1, NULL, Py_TYPE(self));
   461→    Py_DECREF(arr1);
   462→
   463→finish:
   464→    if (out) {
   465→        if (PyArray_AssignArray(out, (PyArrayObject *)ret,
   466→                    NULL, NPY_DEFAULT_ASSIGN_CASTING) < 0) {
   467→            Py_DECREF(ret);
   468→            return NULL;
   469→        }
   470→        Py_DECREF(ret);
   471→        Py_INCREF(out);
   472→        return (PyObject *)out;
   473→    }
   474→    return ret;
   475→}
