   825→/*NUMPY_API
   826→ * Conjugate
   827→ */
   828→NPY_NO_EXPORT PyObject *
   829→PyArray_Conjugate(PyArrayObject *self, PyArrayObject *out)
   830→{
   831→    if (PyArray_ISCOMPLEX(self) || PyArray_ISOBJECT(self) ||
   832→            PyArray_ISUSERDEF(self)) {
   833→        if (out == NULL) {
   834→            return PyArray_GenericUnaryFunction(self,
   835→                                                n_ops.conjugate);
   836→        }
   837→        else {
   838→            return PyArray_GenericBinaryFunction((PyObject *)self,
   839→                                                 (PyObject *)out,
   840→                                                 n_ops.conjugate);
   841→        }
   842→    }
   843→    else {
   844→        PyArrayObject *ret;
   845→        if (!PyArray_ISNUMBER(self)) {
   846→            PyErr_SetString(PyExc_TypeError,
