   723→ */
   724→NPY_NO_EXPORT PyObject *
   725→PyArray_Mean(PyArrayObject *self, int axis, int rtype, PyArrayObject *out)
   726→{
   727→    PyObject *obj1 = NULL, *obj2 = NULL, *ret;
   728→    PyArrayObject *arr;
   729→
   730→    arr = (PyArrayObject *)PyArray_CheckAxis(self, &axis, 0);
   731→    if (arr == NULL) {
   732→        return NULL;
   733→    }
   734→    obj1 = PyArray_GenericReduceFunction(arr, n_ops.add, axis,
   735→                                         rtype, out);
   736→    obj2 = PyFloat_FromDouble((double)PyArray_DIM(arr,axis));
   737→    Py_DECREF(arr);
   738→    if (obj1 == NULL || obj2 == NULL) {
   739→        Py_XDECREF(obj1);
   740→        Py_XDECREF(obj2);
