        if (exp == -1) {
            fastop = n_ops.reciprocal;
        }
        else if (exp == 2) {
            fastop = n_ops.square;
        }
        else {
            return 1;
        }
    }
    else if (PyFloat_CheckExact(o2)) {
        double exp = PyFloat_AsDouble(o2);
        if (exp == 0.5) {
            fastop = n_ops.sqrt;
        }
        else {
            return 1;
        }
