   164→NPY_NO_EXPORT PyObject *
   165→PyArray_GenericReduceFunction(PyArrayObject *m1, PyObject *op, int axis,
   166→                              int rtype, PyArrayObject *out)
   167→{
   168→    PyObject *args, *ret = NULL, *meth;
   169→    PyObject *kwds;
   170→
   171→    args = Py_BuildValue("(Oi)", m1, axis);
   172→    kwds = _get_keywords(rtype, out);
   173→    meth = PyObject_GetAttrString(op, "reduce");
   174→    if (meth && PyCallable_Check(meth)) {
   175→        ret = PyObject_Call(meth, args, kwds);
   176→    }
   177→    Py_DECREF(args);
   178→    Py_DECREF(meth);
   179→    Py_XDECREF(kwds);
   180→    return ret;
   181→}
