   331→static int
   332→fast_scalar_power(PyObject *o1, PyObject *o2, int inplace, PyObject **result)
   333→{
   334→    PyObject *fastop = NULL;
   335→
   336→    if (PyLong_CheckExact(o2)) {
   337→        int overflow = 0;
   338→        long exp = PyLong_AsLongAndOverflow(o2, &overflow);
   339→        if (overflow != 0) {
   340→            return -1;
   341→        }
   342→
   343→        if (exp == -1) {
   344→            fastop = n_ops.reciprocal;
   345→        }
   346→        else if (exp == 2) {
   347→            fastop = n_ops.square;
   348→        }
   349→        else {
   350→            return 1;
   351→        }
   352→    }
   353→    else if (PyFloat_CheckExact(o2)) {
   354→        double exp = PyFloat_AsDouble(o2);
   355→        if (exp == 0.5) {
   356→            fastop = n_ops.sqrt;
   357→        }
   358→        else {
   359→            return 1;
   360→        }
   361→    }
   362→    else {
   363→        return 1;
   364→    }
   365→
   366→    PyArrayObject *a1 = (PyArrayObject *)o1;
   367→    if (PyArray_ISOBJECT(a1)) {
   368→        return 1;
   369→    }
   370→    if (fastop != n_ops.square && !PyArray_ISFLOAT(a1) && !PyArray_ISCOMPLEX(a1)) {
   371→        // we special-case squaring for any array type
   372→        // gh-29388
   373→        return 1;
   374→    }
   375→
   376→    if (inplace || can_elide_temp_unary(a1)) {
   377→        *result = PyArray_GenericInplaceUnaryFunction(a1, fastop);
   378→    }
   379→    else {
   380→        *result = PyArray_GenericUnaryFunction(a1, fastop);
   381→    }
   382→
   383→    return 0;
   384→}
   385→
   386→static PyObject *
   387→array_power(PyObject *a1, PyObject *o2, PyObject *modulo)
   388→{
   389→    PyObject *value = NULL;
   390→
   391→    if (modulo != Py_None) {
   392→        /* modular exponentiation is not implemented (gh-8804) */
   393→        Py_INCREF(Py_NotImplemented);
   394→        return Py_NotImplemented;
   395→    }
   396→
   397→    BINOP_GIVE_UP_IF_NEEDED(a1, o2, nb_power, array_power);
   398→    if (fast_scalar_power(a1, o2, 0, &value) != 0) {
   399→        value = PyArray_GenericBinaryFunction(a1, o2, n_ops.power);
   400→    }
   401→    return value;
   402→}
