   658→    else {
   659→        PyErr_SetString(PyExc_ValueError,
   660→                        "The truth value of an array "
   661→                        "with more than one element is ambiguous. "
   662→                        "Use a.any() or a.all()");
   663→        return -1;
   664→    }
   665→}
   666→
   667→/*
   668→ * Convert the array to a scalar if allowed, and apply the builtin function
   669→ * to it. The where argument is passed onto Py_EnterRecursiveCall when the
   670→ * array contains python objects.
   671→ */
   672→NPY_NO_EXPORT PyObject *
   673→array_scalar_forward(PyArrayObject *v,
   674→                     PyObject *(*builtin_func)(PyObject *),
   675→                     const char *where)
   676→{
