   688→    if (PyDataType_REFCHK(PyArray_DESCR(v))) {
   689→        PyObject *res;
   690→        if (Py_EnterRecursiveCall(where) != 0) {
   691→            Py_DECREF(scalar);
   692→            return NULL;
   693→        }
   694→        res = builtin_func(scalar);
   695→        Py_DECREF(scalar);
   696→        Py_LeaveRecursiveCall();
   697→        return res;
   698→    }
   699→    else {
   700→        PyObject *res;
   701→        res = builtin_func(scalar);
   702→        Py_DECREF(scalar);
   703→        return res;
   704→    }
   705→}
